# scripts/lint_schema.py
import sys, yaml, jsonschema, pathlib

PROMPT_SCHEMA = {
    "type": "object",
    "required": ["id", "version", "model", "max_tokens", "system", "evals"],
    "properties": {
        "id":         {"type": "string", "pattern": "^[a-z][a-z0-9_-]*$"},
        "version":    {"type": "string", "pattern": r"^\d+\.\d+\.\d+$"},
        "model":      {"type": "string"},
        "max_tokens": {"type": "integer", "minimum": 1, "maximum": 8192},
        "system":     {"type": "string", "minLength": 10},
        "evals":      {"type": "array",  "minItems": 1},
    },
    "additionalProperties": False,
}

errors = []
for path in pathlib.Path("prompts/").glob("**/*.yaml"):
    try:
        data = yaml.safe_load(path.read_text())
        jsonschema.validate(data, PROMPT_SCHEMA)
    except yaml.YAMLError as e:
        errors.append(f"{path}: YAML parse error: {e}")
    except jsonschema.ValidationError as e:
        errors.append(f"{path}: Schema error: {e.message}")

if errors:
    for e in errors:
        print(f"::error::{e}")
    sys.exit(1)

print(f"Schema lint passed: {len(list(pathlib.Path('prompts/').glob('**/*.yaml')))} files")

# scripts/check_versions.py
import subprocess, yaml, sys, pathlib, semver

def get_base_version(path: str) -> str | None:
    """Get the version of the file as it exists on the base branch."""
    result = subprocess.run(
        ["git", "show", f"origin/main:{path}"],
        capture_output=True, text=True
    )
    if result.returncode != 0:
        return None  # new file — no version check needed
    return yaml.safe_load(result.stdout).get("version")

errors = []
changed = subprocess.check_output(
    ["git", "diff", "--name-only", "origin/main...HEAD", "--", "prompts/"]
).decode().splitlines()

for rel_path in changed:
    path = pathlib.Path(rel_path)
    if not path.exists() or path.suffix not in (".yaml", ".yml"):
        continue

    current = yaml.safe_load(path.read_text()).get("version", "0.0.0")
    base    = get_base_version(rel_path)

    if base is None:
        continue  # new prompt file — skip

    try:
        if not semver.VersionInfo.parse(current) > semver.VersionInfo.parse(base):
            errors.append(
                f"{rel_path}: version not bumped (was {base}, still {current}). "
                "All prompt changes require a version increment."
            )
    except ValueError as e:
        errors.append(f"{rel_path}: invalid semver '{current}': {e}")

for e in errors:
    print(f"::error::{e}")
sys.exit(1 if errors else 0)

# scripts/run_evals_ci.py
import hashlib, json, os, pathlib, subprocess, sys, yaml

CACHE_DIR  = pathlib.Path(".eval_cache")
CACHE_DIR.mkdir(exist_ok=True)

def content_hash(path: pathlib.Path) -> str:
    return hashlib.sha256(path.read_bytes()).hexdigest()

def load_cache(template_id: str) -> dict | None:
    p = CACHE_DIR / f"{template_id}.json"
    return json.loads(p.read_text()) if p.exists() else None

def save_cache(template_id: str, result: dict):
    (CACHE_DIR / f"{template_id}.json").write_text(json.dumps(result))

changed_files = subprocess.check_output(
    ["git", "diff", "--name-only", "origin/main...HEAD", "--", "prompts/"]
).decode().splitlines()

changed_ids = {
    pathlib.Path(f).stem
    for f in changed_files
    if f.endswith(".yaml")
}

results = {}
for yaml_path in pathlib.Path("prompts/").glob("**/*.yaml"):
    template_id = yaml_path.stem
    if template_id not in changed_ids:
        continue  # unchanged — skip

    h = content_hash(yaml_path)
    cached = load_cache(template_id)
    if cached and cached.get("hash") == h:
        print(f"Cache hit: {template_id}")
        results[template_id] = cached["result"]
        continue

    # Run eval
    proc = subprocess.run(
        ["python", "scripts/run_eval.py", "--template", str(yaml_path)],
        capture_output=True, text=True
    )
    result = json.loads(proc.stdout)
    save_cache(template_id, {"hash": h, "result": result})
    results[template_id] = result

# Check thresholds
exit_code = 0
for tid, r in results.items():
    overall = r["overall_pass_rate"]
    adv     = r.get("adversarial_pass_rate", 1.0)
    if adv < 1.0:
        print(f"::error::EVAL BLOCKED — {tid}: adversarial pass rate {adv:.0%} < 100%")
        exit_code = 1
    elif overall < 0.85:
        print(f"::error::EVAL BLOCKED — {tid}: overall pass rate {overall:.0%} < 85%")
        exit_code = 1
    else:
        print(f"EVAL PASSED — {tid}: {overall:.0%} overall, {adv:.0%} adversarial")

sys.exit(exit_code)

# scripts/scan_injection_surface.py
# Reports any prompt template that does not declare injection_surface
# or that uses user input without XML tag wrapping.
import sys, yaml, pathlib

HIGH_RISK_FIELDS = {"injection_surface"}
errors = []

for path in pathlib.Path("prompts/").glob("**/*.yaml"):
    data = yaml.safe_load(path.read_text())

    if "injection_surface" not in data:
        errors.append(
            f"{path}: missing 'injection_surface' declaration. "
            "Add 'injection_surface: none' if prompt takes no user input, "
            "or 'injection_surface: [field_name, ...]' for each user-controlled field."
        )
        continue

    if data["injection_surface"] == "none":
        continue  # no user input — nothing further to check

    system = data.get("system", "")
    for field in data["injection_surface"]:
        tag = f"<{field}>"
        if tag not in system:
            errors.append(
                f"{path}: injection_surface declares '{field}' but system "
                f"prompt does not wrap it in <{field}>...</{field}> XML tags."
            )

for e in errors:
    print(f"::error::{e}")
sys.exit(1 if errors else 0)
